import React from "react";
import { Link } from "react-router-dom";

const CourseCard = ({ course }) => {
  const { _id, title, description, instructor, duration, category, level, thumbnail, rating, enrolledCount } = course;

  const categoryColors = {
    "Programming Language": { bg: "rgba(108,99,255,0.15)", color: "#6c63ff" },
    "Web Development":      { bg: "rgba(56,189,248,0.15)",  color: "#38bdf8" },
    "Backend Development":  { bg: "rgba(67,217,173,0.15)",  color: "#43d9ad" },
    "Data Science":         { bg: "rgba(251,146,60,0.15)",  color: "#fb923c" },
  };

  const levelColors = {
    Beginner:     { bg: "rgba(67,217,173,0.15)", color: "#43d9ad" },
    Intermediate: { bg: "rgba(255,187,87,0.15)", color: "#ffbb57" },
    Advanced:     { bg: "rgba(255,101,132,0.15)", color: "#ff6584" },
  };

  const catStyle = categoryColors[category] || categoryColors["Web Development"];
  const lvlStyle = levelColors[level] || levelColors["Beginner"];

  const renderStars = (r) => {
    const full = Math.floor(r);
    return "★".repeat(full) + (r % 1 >= 0.5 ? "½" : "") + "☆".repeat(5 - full - (r % 1 >= 0.5 ? 1 : 0));
  };

  return (
    <div className="card h-100 border-0 shadow-sm" style={{
      background: "#1a1a2e",
      border: "1px solid #2a2a4a !important",
      borderRadius: 14,
      transition: "transform 0.2s, box-shadow 0.2s",
      overflow: "hidden",
      cursor: "pointer"
    }}
      onMouseEnter={e => {
        e.currentTarget.style.transform = "translateY(-4px)";
        e.currentTarget.style.boxShadow = "0 12px 40px rgba(108,99,255,0.25)";
        e.currentTarget.style.borderColor = "#6c63ff";
      }}
      onMouseLeave={e => {
        e.currentTarget.style.transform = "translateY(0)";
        e.currentTarget.style.boxShadow = "";
        e.currentTarget.style.borderColor = "#2a2a4a";
      }}
    >
      {/* Thumbnail */}
      <div style={{ position: "relative", height: 180, overflow: "hidden" }}>
        <img
          src={thumbnail || "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=400"}
          alt={title}
          className="w-100 h-100"
          style={{ objectFit: "cover" }}
          onError={e => { e.target.src = "https://images.unsplash.com/photo-1516116216624-53e697fedbea?w=400"; }}
        />
        {/* Level badge */}
        <span className="badge position-absolute" style={{
          top: 12, right: 12,
          background: lvlStyle.bg,
          color: lvlStyle.color,
          borderRadius: 50, fontSize: "0.72rem",
          fontWeight: 700, padding: "4px 10px",
          border: `1px solid ${lvlStyle.color}40`
        }}>
          {level}
        </span>
      </div>

      {/* Card Body */}
      <div className="card-body d-flex flex-column gap-2 p-3">
        {/* Category tag */}
        <span style={{
          display: "inline-block", padding: "3px 10px",
          borderRadius: 50, fontSize: "0.72rem", fontWeight: 700,
          textTransform: "uppercase", letterSpacing: "0.04em",
          background: catStyle.bg, color: catStyle.color,
          alignSelf: "flex-start"
        }}>
          {category}
        </span>

        <h5 className="card-title mb-0 fw-bold" style={{ color: "#e8e8f0", fontSize: "0.98rem", lineHeight: 1.4 }}>
          {title}
        </h5>

        <p className="card-text small mb-0" style={{ color: "#9999bb", lineHeight: 1.6 }}>
          {description?.length > 95 ? description.slice(0, 95) + "..." : description}
        </p>

        {/* Meta row */}
        <div className="d-flex gap-3 flex-wrap mt-auto">
          <span className="small" style={{ color: "#666688" }}>
            <i className="bi bi-person-fill me-1" style={{ color: "#6c63ff" }}></i>{instructor}
          </span>
          <span className="small" style={{ color: "#666688" }}>
            <i className="bi bi-clock me-1" style={{ color: "#6c63ff" }}></i>{duration}
          </span>
        </div>

        {/* Footer */}
        <div className="d-flex align-items-center justify-content-between pt-2" style={{ borderTop: "1px solid #2a2a4a" }}>
          <div className="d-flex align-items-center gap-1">
            <span style={{ color: "#ffbb57", fontSize: "0.82rem" }}>{renderStars(rating || 4.5)}</span>
            <span className="small fw-bold" style={{ color: "#e8e8f0" }}>{(rating || 4.5).toFixed(1)}</span>
            <span className="small" style={{ color: "#666688" }}>({(enrolledCount || 0).toLocaleString()})</span>
          </div>
          <Link to={`/course/${_id}`} className="btn btn-sm fw-semibold" style={{
            background: "#6c63ff", color: "white", border: "none",
            borderRadius: 8, padding: "5px 14px", fontSize: "0.82rem"
          }}>
            View →
          </Link>
        </div>
      </div>
    </div>
  );
};

export default CourseCard;
